const reviewsRaw = $input.all().map(item => item.json);

const URL_BRAND_MAP = {
  "B078V9X189": "Soulflower",
  "B0991ZYLRW": "Soulflower",
  "B0CCHV3J5W": "WOW",
  "B07YNHHH5N": "WOW",
  "B0C6ML81SF": "Mamaearth",
  "B099F3WJKW": "Mamaearth"
};

const seen = new Set();
const cleaned = [];

for (const r of reviewsRaw) {
  const productId = r.Product_Id || "";
  const brand = URL_BRAND_MAP[productId] || "Unknown";

  const reviewText = (r.Body || r.Full_Review || "").trim();
  if (!reviewText) continue;

  const hash = reviewText.slice(0, 60);
  if (seen.has(hash)) continue;
  seen.add(hash);

  const rating = parseFloat(r.Rating) || 0;
  const verified = r.Review_Type === "Verified Purchase";

  const now = new Date();
  const startOfYear = new Date(now.getFullYear(), 0, 1);
  const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);

  cleaned.push({
    brand,
    product_id: productId,
    rating,
    review_text: reviewText,
    title: (r.Title || "").trim(),
    verified,
    week_number: weekNumber,
    date: now.toISOString().split("T")[0]
  });
}

const byBrand = {};
for (const r of cleaned) {
  byBrand[r.brand] = (byBrand[r.brand] || 0) + 1;
}

return [{
  json: {
    cleaned_reviews: cleaned,
    total: cleaned.length,
    by_brand: byBrand
  }
}];

const data = $input.first().json.cleaned_reviews;

const PRODUCT_DETAILS = {
  "B078V9X189": { brand: "Soulflower", category: "Hair Oil",  product_name: "Soulflower Rosemary Hair Oil" },
  "B0991ZYLRW": { brand: "Soulflower", category: "Shampoo",   product_name: "Soulflower Aloevera Fenugreek Shampoo" },
  "B0CCHV3J5W": { brand: "WOW",        category: "Hair Oil",  product_name: "WOW Rosemary Hair Oil" },
  "B07YNHHH5N": { brand: "WOW",        category: "Shampoo",   product_name: "WOW Onion Shampoo" },
  "B0C6ML81SF": { brand: "Mamaearth",  category: "Hair Oil",  product_name: "Mamaearth Rosemary Hair Oil" },
  "B099F3WJKW": { brand: "Mamaearth",  category: "Shampoo",   product_name: "Mamaearth Onion Shampoo" }
};

const categorized = data.map(r => {
  const details = PRODUCT_DETAILS[r.product_id] || {};
  return {
    ...r,
    category: details.category || "Unknown",
    product_name: details.product_name || "Unknown"
  };
});

const byBrand = {};
for (const r of categorized) {
  if (!byBrand[r.brand]) byBrand[r.brand] = [];
  byBrand[r.brand].push(r);
}

const byBrandCategory = {};
for (const r of categorized) {
  const key = `${r.brand}_${r.category}`;
  if (!byBrandCategory[key]) byBrandCategory[key] = [];
  byBrandCategory[key].push(r);
}

const byCategory = {};
for (const r of categorized) {
  if (!byCategory[r.category]) byCategory[r.category] = [];
  byCategory[r.category].push(r);
}

const summary = {};
for (const [key, reviews] of Object.entries(byBrandCategory)) {
  const avgRating = reviews.reduce((a, r) => a + r.rating, 0) / reviews.length;
  summary[key] = {
    count: reviews.length,
    avg_rating: Math.round(avgRating * 100) / 100
  };
}

return [{
  json: {
    cleaned_reviews: categorized,
    by_brand: byBrand,
    by_brand_category: byBrandCategory,
    by_category: byCategory,
    summary,
    total: categorized.length
  }
}];

